#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **segments = (int **)malloc(M * sizeof(int *));
        for (int i = 0; i < M; i++) {
            segments[i] = (int *)malloc(2 * sizeof(int));
            scanf("%d %d", &segments[i][0], &segments[i][1]);
        }
        int result = 1;
        for (int i = 0; i < N; i++) {
            int count = 0;
            for (int j = 0; j < M; j++) {
                if (segments[j][0] - 1 <= i && i <= segments[j][1] - 1) {
                    count++;
                }
            }
            if (count > 0) {
                result = (result * 2) % MOD;
            }
        }
        printf("%d\n", result);
        for (int i = 0; i < M; i++) {
            free(segments[i]);
        }
        free(segments);
    }
    return 0;
}

